package com.pos;
import javax.swing.*; import java.awt.*;
public class ReceiveStockPanel extends JPanel { private final UserSession s; private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);private final JTextField purchase=new JTextField("1",5),product=new JTextField(5),location=new JTextField("1",5),batch=new JTextField(12),expiry=new JTextField(10),qty=new JTextField(7),cost=new JTextField(7);
 public ReceiveStockPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("Stock Receiving"),BorderLayout.WEST);JButton refresh=new JButton("Refresh");h.add(refresh,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel f=new JPanel();f.setBorder(BorderFactory.createTitledBorder("Post Goods Receipt"));for(JComponent c:new JComponent[]{new JLabel("PO ID"),purchase,new JLabel("Product ID"),product,new JLabel("Location ID"),location,new JLabel("Batch"),batch,new JLabel("Expiry"),expiry,new JLabel("Qty"),qty,new JLabel("Cost"),cost})f.add(c);JButton post=new JButton("Receive Stock");f.add(post);add(f,BorderLayout.SOUTH);refresh.addActionListener(e->load());post.addActionListener(e->post());load();}
 private void load(){try{m.load("SELECT g.receipt_id,g.receipt_no,g.purchase_id,g.received_date,p.product_name,i.batch_number,i.expiry_date,i.quantity_received,i.unit_cost FROM goods_receipts g JOIN goods_receipt_items i ON i.receipt_id=g.receipt_id JOIN products p ON p.product_id=i.product_id ORDER BY g.receipt_id DESC");}catch(Exception e){UIUtils.error(this,e);}}
 private void post(){try{POSService.receiveStock(Integer.parseInt(purchase.getText()),Integer.parseInt(product.getText()),Integer.parseInt(location.getText()),batch.getText(),expiry.getText(),Double.parseDouble(qty.getText()),Double.parseDouble(cost.getText()),s.userId);Audit.log(s,"RECEIVE_STOCK",product.getText()+" qty="+qty.getText());load();UIUtils.info(this,"Stock received and inventory updated.");}catch(Exception e){UIUtils.error(this,e);}}
}
